```class Solution {
public:
    bool isSubstringPresent(string s) {
        for(int i = 0; i < s.length() - 1; i++) {
            string substr = s.substr(i, 2);
            if (s.find(substr) != string::npos && reverse.substr(s.length() - substr.length(), substr.length()).find(substr) != string::npos) {
                return true;
            }
        }
        return false;
    }
};
